const STATUS = {
  LOADING: Symbol('loading'),
  SUCCESS: Symbol('success'),
  ERROR: Symbol('error')
};

function handleStatus(status) {
  switch(status) {
    case STATUS.LOADING:
      console.log('Loading...');
      break;
    case STATUS.SUCCESS:
      console.log('Loaded successfully!');
      break;
    case STATUS.ERROR:
      console.log('An error occurred.');
      break;
  }
}

handleStatus(STATUS.LOADING);

