function delay(time) {
  return new Promise(resolve => setTimeout(resolve, time));
}

async function fetchData() {
  await delay(100);
  throw new Error('Oops!');
}

async function start() {
  try {
    await fetchData();
  } catch (error) {
    console.error(error.stack);
  }
}

start();

